import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';

type Post = {
  id: number;
  title: string;
  body: string;
};

type Comment = {
  id: number;
  name: string;
  email: string;
  body: string;
};

type PageProps = {
  params: Promise<{ id: string }>;
};

async function getPost(id: string): Promise<Post | null> {
  const res = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
    next: { revalidate: 300 },
  });

  if (!res.ok) return null;
  return (await res.json()) as Post;
}

async function getComments(id: string): Promise<Comment[]> {
  const res = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });

  if (!res.ok) return [];
  return (await res.json()) as Comment[];
}

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const posts = (await fetch('https://jsonplaceholder.typicode.com/posts', {
    next: { revalidate: 300 },
  }).then((res) => res.json())) as Array<{ id: number }>;

  return posts.slice(0, 10).map((post) => ({ id: String(post.id) }));
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);

  if (!post) {
    return {
      title: 'Post not found - My Blog',
    };
  }

  return {
    title: `${post.title} - My Blog`,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export default async function BlogPostPage({ params }: PageProps) {
  const { id } = await params;
  const [post, comments] = await Promise.all([getPost(id), getComments(id)]);

  if (!post) notFound();

  return (
    <article>
      <Link href="/blog">
        <button type="button">← Back</button>
      </Link>

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}

import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';

type Post = {
  id: number;
  title: string;
  content: string;
};

const posts: Post[] = [
  { id: 1, title: 'First Post', content: 'This is the first post' },
  { id: 2, title: 'Second Post', content: 'This is the second post' },
];

export async function GET() {
  return NextResponse.json(posts);
}

export async function POST(request: NextRequest) {
  const body = (await request.json()) as Partial<Pick<Post, 'title' | 'content'>>;
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json({ error: 'Title and content are required' }, { status: 400 });
  }

  const newPost: Post & { createdAt: string } = {
    id: Date.now(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(newPost, { status: 201 });
}

import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';

type Post = {
  id: number;
  title: string;
  content: string;
};

type RouteContext = {
  params: Promise<{ id: string }>;
};

export async function GET(_request: NextRequest, { params }: RouteContext) {
  const { id } = await params;

  const post: Post & { createdAt: string } = {
    id: Number.parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: NextRequest, { params }: RouteContext) {
  const { id } = await params;
  const body = (await request.json()) as Partial<Pick<Post, 'title' | 'content'>>;
  const { title, content } = body;

  const updatedPost = {
    id: Number.parseInt(id, 10),
    title: title || `Post ${id}`,
    content: content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_request: NextRequest, { params }: RouteContext) {
  const { id } = await params;
  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}

