    }).then((res) => res.json() as Promise<Post[]>),
    import('next/headers').then(({ headers }) => headers()),
  ]);

  const userAgent = headersList.get('user-agent') ?? '';

  return (
    <div>
      <h1>Welcome to My Blog</h1>
      <p>Server-side rendered at: {new Date().toISOString()}</p>
      <p>Your user agent: {userAgent}</p>

      <h2>Recent Posts</h2>
      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <Link href={`/blog/${post.id}`}>{post.title}</Link>
          </li>
        ))}
      </ul>

      <Link href="/blog">
        <button type="button">View All Posts</button>
      </Link>
    </div>
  );
}

